Here is a Java implementation of the Builder pattern for a License class:

java
public class License {
    private final String id;
    private final String licenseeName;
    private final String licenseId;
    private final String environment;
    private final LocalDateTime generatedAt;

    private License(String id, String licenseeName, String licenseId, String environment, LocalDateTime generatedAt) {
        this.id = id;
        this.licenseeName = licenseeName;
        this.licenseId = licenseId;
        this.environment = environment;
        this.generatedAt = generatedAt;
    }

    public static LicenseBuilder builder() {
        return new LicenseBuilder();
    }

    public static class LicenseBuilder {
        private String id;
        private String licenseeName;
        private String licenseId;
        private String environment;
        private LocalDateTime generatedAt;

        private LicenseBuilder() {}

        public LicenseBuilder withId(String id) {
            this.id = id;
            return this;
        }

        public LicenseBuilder withLicenseeName(String licenseeName) {
            this.licenseeName = licenseeName;
            return this;
        }

        public LicenseBuilder withLicenseId(String licenseId) {
            this.licenseId = licenseId;
            return this;
        }

        public LicenseBuilder withEnvironment(String environment) {
            this.environment = environment;
            return this;
        }

        public LicenseBuilder withGeneratedAt(LocalDateTime generatedAt) {
            this.generatedAt = generatedAt;
            return this;
        }

        public License build() {
            return new License(id, licenseeName, licenseId, environment, generatedAt);
        }
    }
}

// Usage example:
val license = License.builder()
    .withId("My license")
    .withLicenseeName("Customer")
    .withLicenseId("XXX-123")
    .withEnvironment("User-acceptance tests")
    .withGeneratedAt(LocalDateTime.now())
    .build();
